import numpy as np

def angle_encode(x, gate='Ry', scaling='linear'):
    # Apply scaling
    if scaling == 'linear':
        theta = np.pi * x
    elif scaling == 'arcsin':
        theta = 2 * np.arcsin(np.clip(x, 0, 1))
    else:
        theta = np.pi * x

    # Build rotation matrix
    c, s = np.cos(theta/2), np.sin(theta/2)

    if gate == 'Rx':
        R = np.array([[c, -1j*s], [-1j*s, c]])
    elif gate == 'Ry':
        R = np.array([[c, -s], [s, c]])
    elif gate == 'Rz':
        R = np.array([[np.exp(-1j*theta/2), 0], [0, np.exp(1j*theta/2)]])
    else:
        raise ValueError(f'Unknown gate: {gate}')

    # Apply to |0⟩
    state = R @ np.array([1, 0], dtype=complex)
    return state

for gate in ['Rx', 'Ry', 'Rz']:
    for scaling in ['linear', 'arcsin']:
        state = angle_encode(0.5, gate, scaling)
        probs = np.abs(state) ** 2
        print(f'{gate}, {scaling}: |0⟩={probs[0]:.4f}, |1⟩={probs[1]:.4f}')
